#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

inline class_T conv_int_fn(const int i) {
#ifdef ENABLE_HP
  return (half2)((half)i, (half)i);
#else
  return (class_T)(i);
#endif
}

inline class_T mad_fn(const class_T a, const class_T b, const class_T c) {
  return a * b + c;
}

inline int equal_fn(const class_T a, const class_T b) {
#ifdef ENABLE_HP
  return all(a == b);
#else
  return a == b;
#endif
}

__kernel void benchmark_func(const class_T seed, __global class_T* g_data) {
  size_t idx, stride, big_stride;

#ifdef BLOCK_STRIDED
  const size_t block_size = get_local_size(0);
  const size_t group_id = get_group_id(0);
  const size_t lid = get_local_id(0);
  const size_t num_groups = get_num_groups(0);

  idx = group_id * block_size * (size_t)ELEMENTS_PER_THREAD + lid;
  stride = block_size;
  big_stride = num_groups * block_size * (size_t)ELEMENTS_PER_THREAD;
#else
  const size_t gid = get_global_id(0);
  const size_t gsize = get_global_size(0);

  idx = gid;
  stride = gsize;
  big_stride = gsize * (size_t)ELEMENTS_PER_THREAD;
#endif

  class_T tmps[ELEMENTS_PER_THREAD];

  for (int k = 0; k < (int)FUSION_DEGREE; k++) {
    for (int j = 0; j < (int)ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + (size_t)j * stride + (size_t)k * big_stride];

      for (int i = 0; i < (int)COMPUTE_ITERATIONS; i++) {
        tmps[j] = mad_fn(tmps[j], tmps[j], seed);
      }
    }

    class_T sum = conv_int_fn(0);
    for (int j = 0; j < (int)ELEMENTS_PER_THREAD; j += 2) {
      sum = mad_fn(tmps[j], tmps[j + 1], sum);
    }

    if (equal_fn(sum, conv_int_fn(-1))) {
      g_data[idx + (size_t)k * big_stride] = sum;
    }
  }
}
